use std::collections::VecDeque;

fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let mut visited = vec![vec![false; n]; m];
    let mut count = 0;

    for i in 0..m {
        for j in 0..n {
            if grid[i][j] != 0 && !visited[i][j] {
                let mut queue = VecDeque::new();
                queue.push_back((i, j));
                visited[i][j] = true;
                let mut sum = 0;
                let mut mod_val = 0;

                while let Some((x, y)) = queue.pop_front() {
                    sum += grid[x][y];
                    mod_val = (mod_val + grid[x][y] as i64) % k;
                    for dx in [-1, 0, 1] {
                        for dy in [-1, 0, 1] {
                            if dx == 0 && dy == 0 { continue; }
                            let nx = x as i32 + dx;
                            let ny = y as i32 + dy;
                            if nx >= 0 && nx < m as i32 && ny >= 0 && ny < n as i32 {
                                if grid[nx as usize][ny as usize] != 0 && !visited[nx as usize][ny as usize] {
                                    visited[nx as usize][ny as usize] = true;
                                    queue.push_back((nx as usize, ny as usize));
                                }
                            }
                        }
                    }
                }

                if mod_val == 0 {
                    count += 1;
                }
            }
        }
    }

    count
}
